import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate } from 'react-router-dom';
import Navbar from './components/Navbar/Navbar';
import Footer from './components/Footer/Footer';
import Hero from './features/landing/Hero';
import HowItWorks from './features/landing/HowItWorks';
import JobServices from './features/landing/JobServices';
import Testimonials from './features/landing/Testimonials';
import CTA from './features/landing/CTA';
import JobListContainer from './features/eksplorasi/JobListContainer';
import Login from './components/auth/Login';
import Register from './components/auth/Register';

// Komponen pembantu tetap di sini
const ViewAllButton = () => {
    const navigate = useNavigate();
    return (
        <div style={{ textAlign: 'center', marginTop: '30px' }}>
            <button 
                onClick={() => navigate('/eksplorasi')} 
                style={{ padding: '12px 32px', background: 'transparent', border: '1px solid #ea580c', color: '#ea580c', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer', transition: '0.3s' }}
            >
                Lihat Semua Lowongan
            </button>
        </div>
    );
};

// Komponen utama App (Sudah di dalam Router context)
const App = () => {
    const [isAuthenticated, setIsAuthenticated] = useState(!!localStorage.getItem('token'));
    const [activeMenu, setActiveMenu] = useState('home');
    const navigate = useNavigate();

    const handleNavigation = (menu) => {
        setActiveMenu(menu);
        if (menu === 'eksplorasi') navigate('/eksplorasi');
        if (menu === 'home') navigate('/');
    };

    return (
        <div style={{ background: '#080402', minHeight: '100vh', color: '#fff' }}>
            <Navbar 
                isAuthenticated={isAuthenticated} 
                activeMenu={activeMenu} 
                setActiveMenu={handleNavigation} 
            />

            <main>
                <Routes>
                    <Route path="/" element={
                        <>
                            <Hero />
                            <HowItWorks />
                            <JobServices />
                            <section style={{ maxWidth: '1100px', margin: '60px auto', padding: '0 20px' }}>
                                <h2 style={{ fontSize: '24px', fontWeight: '800', color: '#fef3c7', marginBottom: '30px' }}>Lowongan Terbaru</h2>
                                <JobListContainer limit={3} />
                                <ViewAllButton />
                            </section>
                            <Testimonials />
                            <CTA />
                        </>
                    } />
                    <Route path="/eksplorasi" element={
                        <div style={{ maxWidth: '1100px', margin: '40px auto', padding: '0 20px' }}>
                            <h1 style={{ fontSize: '2rem', marginBottom: '30px', color: '#fef3c7' }}>Semua Lowongan Kerja</h1>
                            <JobListContainer />
                        </div>
                    } />
                    <Route path="/login" element={<Login onLoginSuccess={() => setIsAuthenticated(true)} />} />
                    <Route path="/register" element={<Register />} />
                </Routes>
            </main>
            <Footer />
        </div>
    );
};

// Komponen pembungkus Router agar App bisa mengakses useNavigate
const AppWrapper = () => (
    <Router>
        <App />
    </Router>
);

export default AppWrapper;
